# OEIS sequence: A396409

from itertools import groupby
trailing1s=lambda n: (~(n+1)&n).bit_length()
def A396409(n): # iterates over runs
    bits=bin(n>>trailing1s(n))[2:]
    onesSeen=0
    steps=0
    for val, grp in groupby(bits):
        l = sum(1 for b in grp)
        if val=='1': onesSeen += l
        steps += l*(2*onesSeen if val=='0' else -1)
    return steps

